import re
from datetime import datetime

# Read the business hours data
with open(var_functions.query_db:10, 'r') as f:
    businesses = json.load(f)

# Read the review ratings data  
with open(var_functions.query_db:11, 'r') as f:
    reviews = json.load(f)

# Calculate average rating per business
ratings_sum = {}
ratings_count = {}

for review in reviews:
    gmap_id = review['gmap_id']
    rating = int(review['rating'])

    if gmap_id not in ratings_sum:
        ratings_sum[gmap_id] = 0
        ratings_count[gmap_id] = 0

    ratings_sum[gmap_id] += rating
    ratings_count[gmap_id] += 1

# Calculate averages
avg_ratings = {}
for gmap_id in ratings_sum:
    avg_ratings[gmap_id] = ratings_sum[gmap_id] / ratings_count[gmap_id]

# Function to parse time string and check if after 6 PM
def is_after_6pm(time_str):
    if 'Open 24 hours' in time_str:
        return True

    # Extract closing time (after the dash)
    if '–' in time_str:
        closing = time_str.split('–')[1]
    elif '-' in time_str:
        closing = time_str.split('-')[1]
    else:
        return False

    # Clean up the time string
    closing = closing.strip()

    # Try to parse different time formats
    try:
        # Handle formats like "9:30PM", "9PM", "10PM"
        if 'PM' in closing:
            closing = closing.replace('PM', '').strip()
            if ':' in closing:
                hour = int(closing.split(':')[0])
                if hour < 12:
                    hour += 12
            else:
                hour = int(closing)
                if hour < 12:
                    hour += 12
            return hour >= 19 or (hour == 18 and ':' in closing)  # 6:01 PM or later
        elif 'AM' in closing:
            # AM times are before 6 PM
            return False
        else:
            # Might be in 24-hour format or have other issues
            return False
    except:
        return False

# Weekday names to check
weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

# Find businesses open after 6 PM on at least one weekday
eligible_businesses = []

for business in businesses:
    gmap_id = business['gmap_id']
    hours_str = business['hours']

    if hours_str == 'None' or not hours_str:
        continue

    try:
        # Parse the hours string (it's a string representation of a list)
        hours_list = eval(hours_str)

        # Check each day
        open_late = False
        for day_hours in hours_list:
            if len(day_hours) >= 2:
                day = day_hours[0]
                time_range = day_hours[1]

                if day in weekdays and is_after_6pm(time_range):
                    open_late = True
                    break

        if open_late and gmap_id in avg_ratings:
            eligible_businesses.append({
                'gmap_id': gmap_id,
                'name': business['name'],
                'hours': hours_str,
                'avg_rating': round(avg_ratings[gmap_id], 2)
            })
    except:
        continue

# Sort by average rating descending
eligible_businesses.sort(key=lambda x: x['avg_rating'], reverse=True)

# Get top 5
top_5 = eligible_businesses[:5]

# Format the result
result = json.dumps(top_5, indent=2)
print('__RESULT__:')
print(result)"}

